// KEIS 搶單通知：收 grab.py POST 進來的 payload，組成 LINE 訊息
const body = $input.first().json.body || $input.first().json;
const USER_ID = "Ufab42c56b2eb9b9a9ff18c367b85a6dd"; // 薛力瑜

let text;
if (body.event === 'alert') {
  text = body.text || '⚠ KEIS 搶單警示';
} else if (body.event === 'daily_summary') {
  // 收盤保底：不管今天有沒有搶到，時段結束都推一則今日戰果（掛 0 那天也一定有訊息）
  const newToday = body.new_today || 0;
  const grabbedToday = body.grabbed_today || 0;
  const recovered = body.recovered || 0;
  const d = body.date || '';
  if (grabbedToday > 0) {
    const missed = newToday - grabbedToday;
    const hint = missed > 0 ? `⚠ 有 ${missed} 筆沒搶到（搶輸/配額滿）` : '✅ 出的全搶到';
    const rec = recovered > 0 ? `（含補回 ${recovered} 筆）` : '';
    text = `☀ KEIS 今日收工 ${d}\n搶到 ${grabbedToday} 筆${rec}｜今天新名單 ${newToday}\n${hint}`;
  } else if (newToday === 0) {
    text = `☀ KEIS 今日收工 ${d}\n掛 0：今天公買沒出貨（整個時段 0 筆新名單）\n✅ 系統正常運作，只是沒貨可搶`;
  } else {
    text = `☀ KEIS 今日收工 ${d}\n掛 0：出了 ${newToday} 筆新名單卻一筆都沒搶到\n⚠ 搶輸/配額滿，回頭看要不要再調快`;
  }
} else {
  const g = body.grabbed || [];
  const lines = g.map(x => `・${x.name} ${x.phone}｜${x.city} ${x.category} ${x.budget}`).join('\n');
  const left = (body.quota_left != null) ? body.quota_left : '?';
  if (body.new_today != null) {
    // 開盤搶到：帶今日累計，一眼分辨貨少 vs 搶輸
    const newToday = body.new_today;
    const grabbedToday = body.grabbed_today;
    const missed = newToday - grabbedToday;
    const hint = missed > 0 ? `⚠ 有 ${missed} 筆沒搶到（搶輸/配額滿）` : '✅ 出的全搶到';
    text = `🎯 KEIS 這批搶到 ${g.length} 筆\n📊 今天累計 新名單 ${newToday} ／ 搶到 ${grabbedToday}｜剩餘配額 ${left}\n${hint}\n\n${lines}`;
  } else {
    // 補漏回查等沒帶今日累計的情況：退回本批數
    text = `🎯 KEIS 搶到 ${g.length} 筆（今日剩餘配額 ${left}）\n\n${lines}`;
  }
}
return [{ json: { userId: USER_ID, text } }];
